const puppeteer = require("puppeteer-core");

(async () => {
  const browser = await puppeteer.connect({
    browserURL: "http://127.0.0.1:9222",
  });

  const pages = await browser.pages();
  const page = pages[0] || (await browser.newPage());

  await page.goto("https://pypi.org/project/requests/#history", {
    waitUntil: "networkidle2",
  });

  await page.setViewport({ width: 1440, height: 2200 });
  await page.waitForSelector("#history");

  const result = await page.evaluate(() => {
    const isPreRelease = version => /[a-zA-Z]/.test(version);

    const rows = Array.from(
      document.querySelectorAll("#history + .release.release--with-date")
    );

    const entries = rows
      .map(row => {
        const link = row.querySelector("h2.release__version a");
        const dateEl = row.querySelector("p.release__version-date");
        if (!link) return null;
        return {
          version: link.textContent.trim(),
          date: dateEl ? dateEl.textContent.replace(/\s+/g, " ").trim() : "",
        };
      })
      .filter(Boolean);

    const latestStable = entries.find(entry => !isPreRelease(entry.version));
    const oldestRelease = entries.length ? entries[entries.length - 1].version : "";

    return {
      latestStable: latestStable ? latestStable.version : "",
      oldestRelease,
      totalReleaseCount: entries.length,
      latestReleaseDate: latestStable ? latestStable.date : "",
    };
  });

  await page.screenshot({
    path: "eval-pypi-history.png",
    fullPage: true,
  });

  console.log(JSON.stringify(result));
  await browser.disconnect();
})();
